import React, { useEffect, useState } from "react";
import { Corrida } from "../interfaces/Corrida";

const estados = [
    { id: 12, sigla: "AC", nome: "Acre" },
    { id: 27, sigla: "AL", nome: "Alagoas" },
    { id: 16, sigla: "AP", nome: "Amapá" },
    { id: 13, sigla: "AM", nome: "Amazonas" },
    { id: 29, sigla: "BA", nome: "Bahia" },
    { id: 23, sigla: "CE", nome: "Ceará" },
    { id: 53, sigla: "DF", nome: "Distrito Federal" },
    { id: 32, sigla: "ES", nome: "Espírito Santo" },
    { id: 52, sigla: "GO", nome: "Goiás" },
    { id: 21, sigla: "MA", nome: "Maranhão" },
    { id: 51, sigla: "MT", nome: "Mato Grosso" },
    { id: 50, sigla: "MS", nome: "Mato Grosso do Sul" },
    { id: 31, sigla: "MG", nome: "Minas Gerais" },
    { id: 15, sigla: "PA", nome: "Pará" },
    { id: 25, sigla: "PB", nome: "Paraíba" },
    { id: 41, sigla: "PR", nome: "Paraná" },
    { id: 26, sigla: "PE", nome: "Pernambuco" },
    { id: 22, sigla: "PI", nome: "Piauí" },
    { id: 33, sigla: "RJ", nome: "Rio de Janeiro" },
    { id: 24, sigla: "RN", nome: "Rio Grande do Norte" },
    { id: 43, sigla: "RS", nome: "Rio Grande do Sul" },
    { id: 11, sigla: "RO", nome: "Rondônia" },
    { id: 14, sigla: "RR", nome: "Roraima" },
    { id: 42, sigla: "SC", nome: "Santa Catarina" },
    { id: 35, sigla: "SP", nome: "São Paulo" },
    { id: 28, sigla: "SE", nome: "Sergipe" },
    { id: 17, sigla: "TO", nome: "Tocantins" },
];

const fetchCidades = async (uf: string) => {
    const url = `https://servicodados.ibge.gov.br/api/v1/localidades/estados/${uf}/municipios?orderBy=nome`;
    const response = await fetch(url);
    const data = await response.json();
    return data.map((cidade: { id: number; nome: string }) => ({
        id: cidade.id,
        nome: cidade.nome,
    }));
};

const statusBadgeClass = (status?: string) => {
    switch (status) {
        case "SOLICITADA":
            return "badge text-bg-warning";
        case "ACEITA":
        case "EM_ANDAMENTO":
            return "badge text-bg-success";
        case "FINALIZADA":
            return "badge text-bg-primary";
        case "CANCELADA":
            return "badge text-bg-danger";
        default:
            return "badge text-bg-secondary";
    }
};

const statusLabel = (status?: string) => {
    if (status === "EM_ANDAMENTO") {
        return "EM ANDAMENTO";
    }
    return status || "-";
};

function CadastrarCorrida() {
    // Idoso
    const [idosoNome, setIdosoNome] = useState("");
    const [idosoCpf, setIdosoCpf] = useState("");
    const [idosoDataNascimento, setIdosoDataNascimento] = useState("");
    const [idosoTelefone, setIdosoTelefone] = useState("");
    const [idosoEmail, setIdosoEmail] = useState("");
    const [idosoAtivo, setIdosoAtivo] = useState(true);
    const [contatoEmergencia, setContatoEmergencia] = useState("");

    // Motorista
    const [motoristaNome, setMotoristaNome] = useState("");
    const [motoristaCpf, setMotoristaCpf] = useState("");
    const [motoristaDataNascimento, setMotoristaDataNascimento] = useState("");
    const [motoristaTelefone, setMotoristaTelefone] = useState("");
    const [motoristaEmail, setMotoristaEmail] = useState("");
    const [motoristaAtivo, setMotoristaAtivo] = useState(true);
    const [cnh, setCnh] = useState("");
    const [disponivel, setDisponivel] = useState(true);
    const [aprovado, setAprovado] = useState(true);

    // Enderecos
    const [origemLogradouro, setOrigemLogradouro] = useState("");
    const [origemNumero, setOrigemNumero] = useState("");
    const [origemCidade, setOrigemCidade] = useState("");
    const [origemEstado, setOrigemEstado] = useState("");
    const [origemCidades, setOrigemCidades] = useState<{ id: number; nome: string }[]>([]);
    const [destinoLogradouro, setDestinoLogradouro] = useState("");
    const [destinoNumero, setDestinoNumero] = useState("");
    const [destinoCidade, setDestinoCidade] = useState("");
    const [destinoEstado, setDestinoEstado] = useState("");
    const [destinoCidades, setDestinoCidades] = useState<{ id: number; nome: string }[]>([]);

    const [statusCorrida, setStatusCorrida] = useState("SOLICITADA");
    const [dataHoraSolicitacao, setDataHoraSolicitacao] = useState("");

    const [corridaInterface, setCorridaInterface] = useState<Corrida | null>(null);
    const [msgCorrida, setMsgCorrida] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [sucessoCadastro, setSucessoCadastro] = useState(false);
    const [mostrarPopup, setMostrarPopup] = useState(false);
    const mostrarCarregando = loading;

    useEffect(() => {
        if (!origemEstado) {
            setOrigemCidades([]);
            setOrigemCidade("");
            return;
        }
        fetchCidades(origemEstado)
            .then((cidades) => {
                setOrigemCidades(cidades);
                setOrigemCidade("");
            })
            .catch(() => {
                setOrigemCidades([]);
            });
    }, [origemEstado]);

    useEffect(() => {
        if (!destinoEstado) {
            setDestinoCidades([]);
            setDestinoCidade("");
            return;
        }
        fetchCidades(destinoEstado)
            .then((cidades) => {
                setDestinoCidades(cidades);
                setDestinoCidade("");
            })
            .catch(() => {
                setDestinoCidades([]);
            });
    }, [destinoEstado]);

    const camposObrigatoriosPreenchidos = origemLogradouro && origemNumero && destinoLogradouro && destinoNumero;

    const handleCadastrarCorrida = async () => {
        if (!camposObrigatoriosPreenchidos) {
            setMsgCorrida('Preencha os campos obrigatórios antes de cadastrar.');
            return;
        }

        setLoading(true);
        setMsgCorrida(null);

        const payload = {
            idoso: {
                nome: idosoNome,
                cpf: idosoCpf,
                dataNascimento: idosoDataNascimento || null,
                telefone: idosoTelefone,
                email: idosoEmail,
                ativo: idosoAtivo,
                contatoEmergencia: contatoEmergencia || null
            },
            motorista: {
                nome: motoristaNome,
                cpf: motoristaCpf,
                dataNascimento: motoristaDataNascimento || null,
                telefone: motoristaTelefone,
                email: motoristaEmail,
                ativo: motoristaAtivo,
                cnh,
                disponivel,
                aprovado
            },
            origem: {
                logradouro: origemLogradouro,
                numero: origemNumero,
                cidade: origemCidade,
                estado: origemEstado
            },
            destino: {
                logradouro: destinoLogradouro,
                numero: destinoNumero,
                cidade: destinoCidade,
                estado: destinoEstado
            },
            statusCorrida,
            dataHoraSolicitacao: dataHoraSolicitacao || null
        };

        try {
            const response = await fetch("http://localhost:8080/corridas/solicitarCorrida", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify(payload),
            });

            if (response.ok) {
                const responseData = await response.json();
                setCorridaInterface(responseData);
                setSucessoCadastro(true);
                setMostrarPopup(true);
                setMsgCorrida("Corrida cadastrada com sucesso!");
            } else {
                const errorText = await response.text();
                setMsgCorrida('Erro ao cadastrar corrida: ' + (errorText || response.statusText || "Erro desconhecido"));
                console.error("Erro na resposta da corrida:", errorText);
            }
        } catch (error) {
            setMsgCorrida("Erro ao cadastrar corrida: " + error.message);
            console.error("Exceção ao cadastrar corrida:", error);
        } finally {
            setLoading(false);
        }
    };

    const handleLimparFormulario = () => {
        setIdosoNome("a");
        setIdosoCpf("a");
        setIdosoDataNascimento("2000-01-01");
        setIdosoTelefone("a");
        setIdosoEmail("a");
        setIdosoAtivo(true);
        setContatoEmergencia("a");
        setMotoristaNome("a");
        setMotoristaCpf("a");
        setMotoristaDataNascimento("2000-01-01");
        setMotoristaTelefone("0");
        setMotoristaEmail("0");
        setMotoristaAtivo(true);
        setCnh("0");
        setDisponivel(true);
        setAprovado(true);  
        setOrigemLogradouro("rua XV de nov");
        setOrigemNumero("211");
        setOrigemCidade("Curitiba");
        setOrigemEstado("PR");
        setOrigemCidades([]);
        setDestinoLogradouro("rua xxx");
        setDestinoNumero("100");
        setDestinoCidade("Redenção");
        setDestinoEstado("PA");
        setDestinoCidades([]);
        setStatusCorrida("SOLICITADA");
        setDataHoraSolicitacao("2026-01-01T00:00:00");
        setCorridaInterface(null);
        setMsgCorrida(null);
        setSucessoCadastro(false);
        setMostrarPopup(false);
    };

    return (
        <div className="container" style={{marginTop: "80px", marginBottom: "20px"}}>
            <h2 className="mb-4" style={{textAlign: "center"}}>Cadastro de Corrida</h2>

            <div className="card p-4 shadow-sm mb-4">
                <form>
                    <div className="row">
                        <div className="col-md-6">
                            <div className="card p-3 mb-3 h-100">
                                <h5 className="mb-3">Formulário do Idoso</h5>
                                <div className="row">
                                    <div className="col-md-6">
                                <div className="mb-3">
                                    <label className="form-label">Nome:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="Nome do idoso"
                                        value={idosoNome}
                                        onChange={(e) => setIdosoNome(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">CPF:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="CPF"
                                        value={idosoCpf}
                                        onChange={(e) => setIdosoCpf(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">Data de Nascimento:</label>
                                    <input
                                        type="date"
                                        className="form-control"
                                        value={idosoDataNascimento}
                                        onChange={(e) => setIdosoDataNascimento(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                    </div>
                                    <div className="col-md-6">
                                <div className="mb-3">
                                    <label className="form-label">Telefone:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="Telefone"
                                        value={idosoTelefone}
                                        onChange={(e) => setIdosoTelefone(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">E-mail:</label>
                                    <input
                                        type="email"
                                        className="form-control"
                                        placeholder="E-mail"
                                        value={idosoEmail}
                                        onChange={(e) => setIdosoEmail(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">Contato de Emergência:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="Contato de emergência"
                                        value={contatoEmergencia}
                                        onChange={(e) => setContatoEmergencia(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="d-flex align-items-center gap-3">
                                    <div className="form-check">
                                        <input
                                            className="form-check-input"
                                            type="checkbox"
                                            checked={idosoAtivo}
                                            onChange={(e) => setIdosoAtivo(e.target.checked)}
                                            id="idosoAtivo"
                                            disabled={loading}
                                        />
                                        <label className="form-check-label" htmlFor="idosoAtivo">
                                            Ativo
                                        </label>
                                    </div>
                                </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="col-md-6">
                            <div className="card p-3 mb-3 h-100">
                                <h5 className="mb-3">Formulário do Motorista</h5>
                                <div className="row">
                                    <div className="col-md-6">
                                <div className="mb-3">
                                    <label className="form-label">Nome:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="Nome do motorista"
                                        value={motoristaNome}
                                        onChange={(e) => setMotoristaNome(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">CPF:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="CPF"
                                        value={motoristaCpf}
                                        onChange={(e) => setMotoristaCpf(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">Data de Nascimento:</label>
                                    <input
                                        type="date"
                                        className="form-control"
                                        value={motoristaDataNascimento}
                                        onChange={(e) => setMotoristaDataNascimento(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">CNH:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="CNH"
                                        value={cnh}
                                        onChange={(e) => setCnh(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="d-flex align-items-center gap-3 mb-3">
                                    <div className="form-check">
                                        <input
                                            className="form-check-input"
                                            type="checkbox"
                                            checked={motoristaAtivo}
                                            onChange={(e) => setMotoristaAtivo(e.target.checked)}
                                            id="motoristaAtivo"
                                            disabled={loading}
                                        />
                                        <label className="form-check-label" htmlFor="motoristaAtivo">
                                            Ativo
                                        </label>
                                    </div>
                                    <div className="form-check">
                                        <input
                                            className="form-check-input"
                                            type="checkbox"
                                            checked={disponivel}
                                            onChange={(e) => setDisponivel(e.target.checked)}
                                            id="motoristaDisponivel"
                                            disabled={loading}
                                        />
                                        <label className="form-check-label" htmlFor="motoristaDisponivel">
                                            Disponível
                                        </label>
                                    </div>
                                    <div className="form-check">
                                        <input
                                            className="form-check-input"
                                            type="checkbox"
                                            checked={aprovado}
                                            onChange={(e) => setAprovado(e.target.checked)}
                                            id="motoristaAprovado"
                                            disabled={loading}
                                        />
                                        <label className="form-check-label" htmlFor="motoristaAprovado">
                                            Aprovado
                                        </label>
                                    </div>
                                </div>
                                    </div>
                                    <div className="col-md-6">
                                <div className="mb-3">
                                    <label className="form-label">Telefone:</label>
                                    <input
                                        type="text"
                                        className="form-control"
                                        placeholder="Telefone"
                                        value={motoristaTelefone}
                                        onChange={(e) => setMotoristaTelefone(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">E-mail:</label>
                                    <input
                                        type="email"
                                        className="form-control"
                                        placeholder="E-mail"
                                        value={motoristaEmail}
                                        onChange={(e) => setMotoristaEmail(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                <div className="mb-3">
                                    <label className="form-label">E-mail:</label>
                                    <input
                                        type="email"
                                        className="form-control"
                                        placeholder="E-mail"
                                        value={motoristaEmail}
                                        onChange={(e) => setMotoristaEmail(e.target.value)}
                                        disabled={loading}
                                    />
                                </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="row">
                        <div className="col-md-6">
                            <div className="mb-3">
                                <label className="form-label">Origem - Logradouro: <span className="text-danger">*</span></label>
                                <input
                                    type="text"
                                    className="form-control"
                                    placeholder="Rua/Av"
                                    value={origemLogradouro}
                                    onChange={(e) => setOrigemLogradouro(e.target.value)}
                                    disabled={loading}
                                    required
                                />
                            </div>
                            <div className="mb-3">
                                <label className="form-label">Origem - Número: <span className="text-danger">*</span></label>
                                <input
                                    type="text"
                                    className="form-control"
                                    placeholder="Número"
                                    value={origemNumero}
                                    onChange={(e) => setOrigemNumero(e.target.value)}
                                    disabled={loading}
                                    required
                                />
                            </div>
                            <div className="mb-3">
                                <label className="form-label">Origem - Estado:</label>
                                <select
                                    className="form-select"
                                    value={origemEstado}
                                    onChange={(e) => setOrigemEstado(e.target.value)}
                                    disabled={loading}
                                >
                                    <option value="">Selecione o estado</option>
                                    {estados.map((estado) => (
                                        <option key={estado.sigla} value={estado.sigla}>
                                            {estado.nome}
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div className="mb-3">
                                <label className="form-label">Origem - Cidade:</label>
                                <select
                                    className="form-select"
                                    value={origemCidade}
                                    onChange={(e) => setOrigemCidade(e.target.value)}
                                    disabled={loading || !origemEstado}
                                >
                                    <option value="">
                                        {origemEstado ? "Selecione a cidade" : "Selecione o estado"}
                                    </option>
                                    {origemCidades.map((cidade) => (
                                        <option key={cidade.id} value={cidade.nome}>
                                            {cidade.nome}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="col-md-6">
                            <div className="mb-3">
                                <label className="form-label">Destino - Logradouro: <span className="text-danger">*</span></label>
                                <input
                                    type="text"
                                    className="form-control"
                                    placeholder="Rua/Av"
                                    value={destinoLogradouro}
                                    onChange={(e) => setDestinoLogradouro(e.target.value)}
                                    disabled={loading}
                                    required
                                />
                            </div>
                            <div className="mb-3">
                                <label className="form-label">Destino - Número: <span className="text-danger">*</span></label>
                                <input
                                    type="text"
                                    className="form-control"
                                    placeholder="Número"
                                    value={destinoNumero}
                                    onChange={(e) => setDestinoNumero(e.target.value)}
                                    disabled={loading}
                                    required
                                />
                            </div>
                            <div className="mb-3">
                                <label className="form-label">Destino - Estado:</label>
                                <select
                                    className="form-select"
                                    value={destinoEstado}
                                    onChange={(e) => setDestinoEstado(e.target.value)}
                                    disabled={loading}
                                >
                                    <option value="">Selecione o estado</option>
                                    {estados.map((estado) => (
                                        <option key={estado.sigla} value={estado.sigla}>
                                            {estado.nome}
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div className="mb-3">
                                <label className="form-label">Destino - Cidade:</label>
                                <select
                                    className="form-select"
                                    value={destinoCidade}
                                    onChange={(e) => setDestinoCidade(e.target.value)}
                                    disabled={loading || !destinoEstado}
                                >
                                    <option value="">
                                        {destinoEstado ? "Selecione a cidade" : "Selecione o estado"}
                                    </option>
                                    {destinoCidades.map((cidade) => (
                                        <option key={cidade.id} value={cidade.nome}>
                                            {cidade.nome}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>
                    <div className="row">
                        <div className="col-md-6">
                            <div className="mb-3">
                                <label className="form-label">Status da Corrida:</label>
                                <select
                                    className="form-select"
                                    value={statusCorrida}
                                    onChange={(e) => setStatusCorrida(e.target.value)}
                                    disabled={loading}
                                >
                                    <option value="SOLICITADA">SOLICITADA</option>
                                    <option value="ACEITA">ACEITA</option>
                                    <option value="EM_ANDAMENTO">EM ANDAMENTO</option>
                                    <option value="FINALIZADA">FINALIZADA</option>
                                    <option value="CANCELADA">CANCELADA</option>
                                </select>
                            </div>
                        </div>
                        <div className="col-md-6">
                            <div className="mb-3">
                                <label className="form-label">Data/Hora de Solicitação:</label>
                                <input
                                    type="datetime-local"
                                    className="form-control"
                                    value={dataHoraSolicitacao}
                                    onChange={(e) => setDataHoraSolicitacao(e.target.value)}
                                    disabled={loading}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="d-flex gap-2 mt-3">
                        <button
                            type="button"
                            className="btn btn-primary"
                            onClick={handleCadastrarCorrida}
                            disabled={!camposObrigatoriosPreenchidos || loading}
                        >
                            {loading ? (
                                <>
                                    <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                                    Cadastrando...
                                </>
                            ) : "Cadastrar Corrida"}
                        </button>

                        <button
                            type="button"
                            className="btn btn-secondary"
                            onClick={handleLimparFormulario}
                            disabled={loading}
                        >
                            Preencher Campos
                        </button>
                    </div>

                    {msgCorrida && (
                        <div className={`alert ${sucessoCadastro ? "alert-success" : "alert-danger"} mt-3`}>
                            {msgCorrida}
                        </div>
                    )}
                </form>
            </div>

            {mostrarPopup && corridaInterface && (
                <div
                    className="modal fade show"
                    style={{display: "block", backgroundColor: "rgba(0,0,0,0.5)"}}
                    role="dialog"
                    aria-modal="true"
                >
                    <div className="modal-dialog modal-lg modal-dialog-centered" role="document">
                        <div className="modal-content">
                            <div className="modal-header">
                                <h5 className="modal-title">Corrida cadastrada</h5>
                                <button
                                    type="button"
                                    className="btn-close"
                                    aria-label="Fechar"
                                    onClick={() => setMostrarPopup(false)}
                                ></button>
                            </div>
                            <div className="modal-body">
                                <div className="table-responsive">
                                    <table className="table table-bordered">
                                        <tbody>
                                        <tr>
                                            <th style={{width: "200px"}}>ID</th>
                                            <td>{corridaInterface.id}</td>
                                        </tr>
                                        <tr>
                                            <th>Status</th>
                                            <td>
                                                <span className={statusBadgeClass(corridaInterface.statusCorrida)}>
                                                    {statusLabel(corridaInterface.statusCorrida)}
                                                </span>
                                            </td>
                                        </tr>
                                        <tr>
                                            <th>Idoso</th>
                                            <td>{corridaInterface.idoso?.nome || "-"}</td>
                                        </tr>
                                        <tr>
                                            <th>Motorista</th>
                                            <td>{corridaInterface.motorista?.nome || "-"}</td>
                                        </tr>
                                        <tr>
                                            <th>Origem</th>
                                            <td>
                                                {corridaInterface.origem
                                                    ? `${corridaInterface.origem.logradouro}, ${corridaInterface.origem.numero} - ${corridaInterface.origem.cidade}/${corridaInterface.origem.estado}`
                                                    : "-"}
                                            </td>
                                        </tr>
                                        <tr>
                                            <th>Destino</th>
                                            <td>
                                                {corridaInterface.destino
                                                    ? `${corridaInterface.destino.logradouro}, ${corridaInterface.destino.numero} - ${corridaInterface.destino.cidade}/${corridaInterface.destino.estado}`
                                                    : "-"}
                                            </td>
                                        </tr>
                                        <tr>
                                            <th>Data/Hora</th>
                                            <td>{corridaInterface.dataHoraSolicitacao}</td>
                                        </tr>
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                            <div className="modal-footer">
                                <button
                                    type="button"
                                    className="btn btn-secondary"
                                    onClick={() => setMostrarPopup(false)}
                                >
                                    Fechar
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
            {mostrarCarregando && <div className="loading-footer">Carregando</div>}
        </div>
    );
}

export default CadastrarCorrida;
